import { useMutation, useQueryClient } from "@tanstack/react-query";
import {
  type FormEvent,
  useCallback,
  useEffect,
  useReducer,
  useRef,
} from "react";

import {
  type AdjustmentSelection,
  getAdjustableViews,
  type ViewMode,
  type ViewportAnchor,
} from "@/components/format-workspace/types";
import { orpc } from "@/lib/orpc";

import {
  createInitialState,
  sessionReducer,
} from "./adjustment-session-reducer";

function extractErrorMessage(error: unknown, fallback: string): string {
  return error instanceof Error ? error.message : fallback;
}

export function useAdjustmentSession(view: ViewMode, jobId: string) {
  const sectionRef = useRef<HTMLElement | null>(null);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const [state, dispatch] = useReducer(
    sessionReducer,
    undefined,
    createInitialState,
  );
  const queryClient = useQueryClient();

  const createSession = useMutation(
    orpc.adjustments.createSession.mutationOptions(),
  );

  const appendMessage = useMutation(
    orpc.adjustments.appendMessage.mutationOptions({
      onSuccess: (nextDetail) => {
        dispatch({ type: "APPEND_MESSAGE_SUCCESS", view, detail: nextDetail });
        if (nextDetail.session.status === "applied")
          queryClient.invalidateQueries({ queryKey: orpc.rules.list.key() });
      },
      onError: (error) => {
        dispatch({
          type: "SET_SESSION_ERROR",
          error: extractErrorMessage(
            error,
            "Anpassungsnachricht konnte nicht gespeichert werden.",
          ),
        });
      },
    }),
  );

  const discardSession = useMutation(
    orpc.adjustments.discard.mutationOptions({
      onSuccess: () => dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view }),
      onError: (error) => {
        if (state.activeSessionDetail?.session.status === "applied") {
          dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view });
        } else {
          dispatch({
            type: "SET_SESSION_ERROR",
            error: extractErrorMessage(
              error,
              "Anpassungssession konnte nicht verworfen werden.",
            ),
          });
        }
      },
    }),
  );

  // Derived values
  const isAdjustableView = getAdjustableViews().has(view);
  const isAdjustModeEnabled = state.adjustModeByView[view];
  const activeSelection = state.selectionByView[view];

  // Disable adjust mode when switching to a non-adjustable view
  useEffect(() => {
    if (!isAdjustableView && isAdjustModeEnabled)
      dispatch({ type: "SET_ADJUST_MODE", view, enabled: false });
  }, [isAdjustModeEnabled, isAdjustableView, view]);

  // Debounced session creation on selection change
  useEffect(() => {
    const currentSelection = state.selectionByView[view];
    const activeSelectionKey = state.sessionSelectionKeyByView[view];
    if (!isAdjustModeEnabled || !isAdjustableView || !currentSelection) return;

    const nextSelectionKey = JSON.stringify(currentSelection);
    if (
      activeSelectionKey === nextSelectionKey &&
      state.activeSessionDetail?.session.importId === jobId
    )
      return;

    if (debounceRef.current !== null) clearTimeout(debounceRef.current);

    debounceRef.current = setTimeout(() => {
      dispatch({ type: "SET_SESSION_ERROR", error: null });
      createSession.mutate(
        { importId: jobId, selection: currentSelection, targetFormat: view },
        {
          onSuccess: (detail) => {
            dispatch({ type: "SET_ACTIVE_SESSION_DETAIL", detail });
            dispatch({
              type: "SET_SESSION_SELECTION_KEY",
              view,
              key: nextSelectionKey,
            });
          },
          onError: (error) => {
            dispatch({
              type: "SET_SESSION_ERROR",
              error: extractErrorMessage(
                error,
                "Anpassungssession konnte nicht erstellt werden.",
              ),
            });
          },
        },
      );
    }, 250);

    return () => {
      if (debounceRef.current !== null) clearTimeout(debounceRef.current);
    };
  }, [
    state.selectionByView[view],
    state.sessionSelectionKeyByView[view],
    state.activeSessionDetail,
    createSession.mutate,
    isAdjustModeEnabled,
    isAdjustableView,
    jobId,
    view,
  ]);

  const toggleAdjustMode = useCallback(() => {
    if (!isAdjustableView) return;
    const nextEnabled = !state.adjustModeByView[view];
    dispatch({ type: "SET_ADJUST_MODE", view, enabled: nextEnabled });
    dispatch({ type: "SET_GUIDE_DISMISSED", view, dismissed: false });
    if (!nextEnabled) dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view });
  }, [isAdjustableView, state.adjustModeByView, view]);

  const handleSelectionChange = useCallback(
    (selection: AdjustmentSelection, anchor: ViewportAnchor) => {
      const container = sectionRef.current;
      const r = container?.getBoundingClientRect();
      const scrollTop = container?.scrollTop ?? 0;
      const adjusted = r
        ? {
            top: anchor.top - r.top + scrollTop,
            bottom: anchor.bottom - r.top + scrollTop,
            left: anchor.left - r.left,
            width: anchor.width,
            height: anchor.height,
          }
        : anchor;
      dispatch({
        type: "SELECTION_CHANGED",
        view,
        selection,
        anchor: adjusted,
      });
    },
    [view],
  );

  // Stable refs for values used in callbacks — prevents useCallback from
  // getting new references when mutation objects or state change.
  const latestRef = useRef({
    activeSessionDetail: state.activeSessionDetail,
    draftMessageByView: state.draftMessageByView,
    appendMutate: appendMessage.mutate,
    discardMutate: discardSession.mutate,
  });
  latestRef.current = {
    activeSessionDetail: state.activeSessionDetail,
    draftMessageByView: state.draftMessageByView,
    appendMutate: appendMessage.mutate,
    discardMutate: discardSession.mutate,
  };

  const handleSubmitMessage = useCallback(
    (event: FormEvent<HTMLFormElement>) => {
      event.preventDefault();
      const { activeSessionDetail, draftMessageByView, appendMutate } =
        latestRef.current;
      if (!activeSessionDetail) return;
      const content = draftMessageByView[view].trim();
      if (!content) return;
      dispatch({ type: "SET_SESSION_ERROR", error: null });
      appendMutate({
        sessionId: activeSessionDetail.session.id,
        content,
      });
    },
    [view],
  );

  const handleDiscardSession = useCallback(() => {
    const { activeSessionDetail, discardMutate } = latestRef.current;
    if (!activeSessionDetail) {
      dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view });
      return;
    }
    dispatch({ type: "SET_SESSION_ERROR", error: null });
    discardMutate({ sessionId: activeSessionDetail.session.id });
  }, [view]);

  const handleDraftMessageChange = useCallback(
    (value: string) => dispatch({ type: "SET_DRAFT_MESSAGE", view, value }),
    [view],
  );

  const setReplyVisible = useCallback(
    (visible: boolean) =>
      dispatch({ type: "SET_REPLY_VISIBLE", view, visible }),
    [view],
  );

  const setGuideDismissed = useCallback(
    (dismissed: boolean) =>
      dispatch({ type: "SET_GUIDE_DISMISSED", view, dismissed }),
    [view],
  );

  const clearCurrentAdjustmentState = useCallback(
    (targetView: ViewMode) =>
      dispatch({ type: "CLEAR_ADJUSTMENT_STATE", view: targetView }),
    [],
  );

  return {
    sectionRef,
    adjustModeEnabled: isAdjustModeEnabled,
    activeSessionDetail: state.activeSessionDetail,
    activeSelection,
    activeAnchor: state.anchorByView[view],
    activeDraftMessage: state.draftMessageByView[view],
    activeSessionError: state.sessionError,
    activeSessionLoading: createSession.isPending,
    isSubmitting: appendMessage.isPending,
    isDiscarding: discardSession.isPending,
    showGuide:
      isAdjustModeEnabled &&
      !activeSelection &&
      !state.guideDismissedByView[view],
    replyVisible: state.replyVisibleByView[view],
    guideDismissed: state.guideDismissedByView[view],
    toggleAdjustMode,
    handleSelectionChange,
    handleDraftMessageChange,
    handleSubmitMessage,
    handleDiscardSession,
    clearCurrentAdjustmentState,
    setReplyVisible,
    setGuideDismissed,
  };
}

import type { AdjustmentSessionDetail } from "@chat-exporter/shared";
import {
  autoUpdate,
  flip,
  offset,
  shift,
  useFloating,
} from "@floating-ui/react";
import { X } from "lucide-react";
import {
  type FormEvent,
  memo,
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
} from "react";
import { adjustmentLabels } from "@/components/format-workspace/labels";
import type {
  FloatingAdjustmentAnchor,
  ViewMode,
} from "@/components/format-workspace/types";

type AdjustmentPopoverProps = {
  anchor: FloatingAdjustmentAnchor | null;
  containerRef: React.RefObject<HTMLElement | null>;
  draftMessage: string;
  error: string | null;
  isLoading: boolean;
  isSubmitting: boolean;
  onClose: () => void;
  onDraftMessageChange: (value: string) => void;
  onRejectLastChange: (() => void) | undefined;
  onSubmitMessage: (event: FormEvent<HTMLFormElement>) => void;
  open: boolean;
  sessionDetail: AdjustmentSessionDetail | null;
  showReply: boolean;
  view: ViewMode;
};

function getLastAssistantMessage(
  sessionDetail: AdjustmentSessionDetail | null,
) {
  return (
    sessionDetail?.messages
      .slice()
      .reverse()
      .find((message) => message.role === "assistant")?.content ?? null
  );
}

/** Debounce loading indicator to avoid flashing the overlay for fast API responses. */
const LOADING_DEBOUNCE_MS = 300;

function useDebouncedLoading(isLoading: boolean) {
  const [showLoading, setShowLoading] = useState(false);

  useEffect(() => {
    if (!isLoading) {
      setShowLoading(false);
      return;
    }
    const timer = setTimeout(() => setShowLoading(true), LOADING_DEBOUNCE_MS);
    return () => clearTimeout(timer);
  }, [isLoading]);

  return showLoading;
}

// Isolated textarea — prevents re-renders from parent state changes (isLoading, sessionDetail)
// from touching the textarea DOM node, which would cause a placeholder repaint.
const DraftTextarea = memo(function DraftTextarea({
  value,
  placeholder,
  onChangeRef,
}: {
  value: string;
  placeholder: string;
  onChangeRef: React.RefObject<(value: string) => void>;
}) {
  return (
    <textarea
      data-testid="adjustment-draft-message"
      className="min-h-24 w-full rounded-2xl border border-border/80 bg-background px-3 py-3 text-sm text-foreground outline-none placeholder:text-muted-foreground focus:border-primary/50 focus:ring-2 focus:ring-primary/20"
      placeholder={placeholder}
      value={value}
      onChange={(event) => onChangeRef.current?.(event.target.value)}
    />
  );
});

const PopoverContent = memo(function PopoverContent({
  draftMessage,
  error,
  isLoading,
  isSubmitting,
  onClose,
  onDraftMessageChange,
  onRejectLastChange,
  onSubmitMessage,
  sessionDetail,
  showReply,
  view: _view,
}: Omit<AdjustmentPopoverProps, "anchor" | "containerRef" | "open">) {
  const lastAssistantMessage = getLastAssistantMessage(sessionDetail);
  const showLoadingOverlay = useDebouncedLoading(isLoading);

  const onChangeRef = useRef(onDraftMessageChange);
  onChangeRef.current = onDraftMessageChange;

  const placeholder = showReply
    ? adjustmentLabels.followUpPlaceholder
    : adjustmentLabels.adjustmentPlaceholder;

  return (
    <div className="overflow-hidden rounded-[1.4rem] border border-border bg-background shadow-[0_24px_80px_-32px_rgba(15,23,42,0.5)]">
      <div className="flex items-center justify-between gap-3 border-b border-border/80 px-4 py-3">
        <p className="text-[11px] font-semibold uppercase tracking-[0.2em] text-primary">
          {adjustmentLabels.createRuleLabel}
        </p>
        <button
          className="rounded-full p-1 text-muted-foreground transition hover:bg-foreground/5 hover:text-foreground"
          type="button"
          onClick={onClose}
        >
          <span className="sr-only">{adjustmentLabels.closeLabel}</span>
          <X className="h-4 w-4" />
        </button>
      </div>

      <div className="relative overflow-y-auto px-4 py-4">
        {error ? (
          <div
            data-testid="adjustment-error"
            className="absolute inset-x-4 top-4 z-10 rounded-2xl border border-red-300/40 bg-red-100/70 px-3 py-3 text-sm text-red-900"
          >
            {error}
          </div>
        ) : null}

        {showLoadingOverlay ? (
          <div className="absolute inset-x-4 top-4 z-10 rounded-2xl border border-border/80 bg-card/95 px-3 py-3 text-sm text-muted-foreground">
            {adjustmentLabels.loadingMessage}
          </div>
        ) : null}

        {showReply && lastAssistantMessage ? (
          <div
            data-testid="adjustment-last-reply"
            className="mb-3 rounded-2xl border border-primary/20 bg-primary/5 px-3 py-3 text-sm text-foreground"
          >
            <p className="whitespace-pre-wrap">{lastAssistantMessage}</p>
          </div>
        ) : null}

        <form className="space-y-3" onSubmit={onSubmitMessage}>
          {/* biome-ignore lint/a11y/noLabelWithoutControl: DraftTextarea contains a textarea */}
          <label className="block text-sm text-foreground">
            <span className="sr-only">{adjustmentLabels.inputLabel}</span>
            <DraftTextarea
              value={draftMessage}
              placeholder={placeholder}
              onChangeRef={onChangeRef}
            />
          </label>

          <p className="px-3 text-sm text-muted-foreground">
            {showReply
              ? adjustmentLabels.appliedHint
              : adjustmentLabels.defaultHint}
          </p>

          <div className="flex items-center justify-between gap-3">
            <button
              className="inline-flex items-center justify-center rounded-xl border border-border/80 bg-background px-4 py-2 text-sm font-medium text-foreground transition hover:bg-foreground/5"
              type="button"
              onClick={onClose}
            >
              {adjustmentLabels.cancel}
            </button>
            {showReply && !isLoading && onRejectLastChange != null ? (
              <button
                className="inline-flex items-center justify-center rounded-xl border border-border/80 bg-background px-4 py-2 text-sm font-medium text-foreground transition hover:bg-foreground/5"
                type="button"
                onClick={onRejectLastChange}
              >
                {adjustmentLabels.discard}
              </button>
            ) : null}
            <button
              data-testid="adjustment-send"
              className="inline-flex items-center justify-center rounded-xl bg-primary px-4 py-2 text-sm font-medium text-primary-foreground transition hover:opacity-95 disabled:cursor-not-allowed disabled:opacity-60"
              disabled={
                isLoading || isSubmitting || draftMessage.trim().length === 0
              }
              type="submit"
            >
              {isSubmitting
                ? adjustmentLabels.sendPending
                : adjustmentLabels.send}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
});

export function AdjustmentPopover({
  anchor,
  containerRef,
  open,
  ...contentProps
}: AdjustmentPopoverProps) {
  const { refs, floatingStyles, isPositioned } = useFloating({
    open,
    placement: "top-start",
    middleware: [offset(12), flip({ padding: 16 }), shift({ padding: 16 })],
    whileElementsMounted: autoUpdate,
  });

  useLayoutEffect(() => {
    if (!anchor) return;
    refs.setPositionReference({
      getBoundingClientRect() {
        const container = containerRef.current;
        if (!container) {
          return {
            x: 0,
            y: 0,
            top: 0,
            left: 0,
            bottom: 0,
            right: 0,
            width: 0,
            height: 0,
          };
        }
        const cr = container.getBoundingClientRect();
        const scrollTop = container.scrollTop;
        const top = anchor.top - scrollTop + cr.top;
        const left = anchor.left + cr.left;
        return {
          x: left,
          y: top,
          top,
          left,
          bottom: top + anchor.height,
          right: left + anchor.width,
          width: anchor.width,
          height: anchor.height,
        };
      },
    });
  }, [anchor, containerRef, refs]);

  const visible = open && isPositioned;

  return (
    <div
      ref={refs.setFloating}
      data-testid={`adjustment-popover-${contentProps.view}`}
      className="z-50 w-[28rem] max-w-[calc(100vw-2rem)]"
      style={{
        ...floatingStyles,
        visibility: visible ? "visible" : "hidden",
        pointerEvents: visible ? "auto" : "none",
      }}
      aria-hidden={!visible}
    >
      <PopoverContent {...contentProps} />
    </div>
  );
}

import type {
  AdjustmentSessionDetail,
  FormatRule,
} from "@chat-exporter/shared";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { useState } from "react";
import {
  getAdjustableViews,
  type ViewMode,
} from "@/components/format-workspace/types";
import { useRuleExplanations } from "@/components/format-workspace/use-rule-explanations";
import { orpc } from "@/lib/orpc";
import { demoteFormatRule, promoteFormatRule, rpc } from "@/lib/rpc";

function errorMsg(error: unknown, fallback: string): string {
  return error instanceof Error ? error.message : fallback;
}

function removeKey(
  rec: Record<string, boolean>,
  key: string,
): Record<string, boolean> {
  const next = { ...rec };
  delete next[key];
  return next;
}

export function useFormatRules(view: ViewMode, jobId: string) {
  const queryClient = useQueryClient();
  const isAdjustableView = getAdjustableViews().has(view);
  const rulesQuery = useQuery({
    ...orpc.rules.list.queryOptions({
      input: { importId: jobId, format: view },
    }),
    enabled: isAdjustableView,
  });
  const activeRules: FormatRule[] = rulesQuery.data ?? [];

  const [disablingRuleById, setDisablingRuleById] = useState<
    Record<string, boolean>
  >({});
  const [promotingRuleById, setPromotingRuleById] = useState<
    Record<string, boolean>
  >({});
  const [hoveredRuleId, setHoveredRuleId] = useState<string | null>(null);
  const [disableError, setDisableError] = useState<string | null>(null);
  const [promoteError, setPromoteError] = useState<string | null>(null);
  const explanations = useRuleExplanations();
  const invalidateRules = () =>
    queryClient.invalidateQueries({ queryKey: orpc.rules.list.key() });

  async function handleDisableRule(ruleId: string): Promise<boolean> {
    setDisablingRuleById((c) => ({ ...c, [ruleId]: true }));
    setDisableError(null);
    try {
      await rpc.rules.disable({ id: ruleId });
      invalidateRules();
      setHoveredRuleId((c) => (c === ruleId ? null : c));
      return true;
    } catch (error) {
      setDisableError(
        errorMsg(error, "Regel konnte nicht deaktiviert werden."),
      );
      return false;
    } finally {
      setDisablingRuleById((c) => removeKey(c, ruleId));
    }
  }

  async function handleRejectLastChange(
    sessionDetail: AdjustmentSessionDetail,
  ): Promise<boolean> {
    const findMatch = (rules: FormatRule[]) =>
      rules.find(
        (r) =>
          r.sourceSessionId === sessionDetail.session.id &&
          r.status === "active",
      );
    let matchingRule = findMatch(activeRules);
    if (!matchingRule) {
      try {
        const freshRules = await rpc.rules.list({
          importId: jobId,
          format: view,
        });
        invalidateRules();
        matchingRule = findMatch(freshRules);
      } catch {
        return false;
      }
    }
    if (!matchingRule) return false;
    return handleDisableRule(matchingRule.id);
  }

  async function handlePromoteRule(ruleId: string): Promise<boolean> {
    setPromotingRuleById((c) => ({ ...c, [ruleId]: true }));
    setPromoteError(null);
    try {
      await promoteFormatRule(ruleId);
      invalidateRules();
      return true;
    } catch (error) {
      setPromoteError(
        errorMsg(error, "Regel konnte nicht hochgestuft werden."),
      );
      return false;
    } finally {
      setPromotingRuleById((c) => removeKey(c, ruleId));
    }
  }

  async function handleDemoteRule(ruleId: string): Promise<boolean> {
    setPromotingRuleById((c) => ({ ...c, [ruleId]: true }));
    setPromoteError(null);
    try {
      await demoteFormatRule(ruleId, jobId);
      invalidateRules();
      return true;
    } catch (error) {
      setPromoteError(
        errorMsg(error, "Regel konnte nicht herabgestuft werden."),
      );
      return false;
    } finally {
      setPromotingRuleById((c) => removeKey(c, ruleId));
    }
  }

  return {
    activeRules,
    disablingRuleById,
    promotingRuleById,
    hoveredRuleId,
    disableError,
    promoteError,
    setHoveredRuleId,
    clearDisableError: () => setDisableError(null),
    clearPromoteError: () => setPromoteError(null),
    handleDisableRule,
    handlePromoteRule,
    handleDemoteRule,
    handleRejectLastChange,
    ...explanations,
  };
}

import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { act, renderHook } from "@testing-library/react";
import type { ReactNode } from "react";
import { createElement } from "react";
import { beforeEach, describe, expect, test, vi } from "vitest";

import { useMessageEdits } from "./use-message-edits";

const mockMutate = vi.fn();
const mockMutateAsync = vi.fn();
let _mockIsPending = false;

vi.mock("@/lib/orpc", () => ({
  orpc: {
    edits: {
      listForSnapshot: {
        queryOptions: () => ({
          queryKey: ["edits", "listForSnapshot"],
          queryFn: () => Promise.resolve([]),
        }),
        key: () => ["edits", "listForSnapshot"],
      },
      save: {
        mutationOptions: (opts: {
          onSuccess?: () => void;
          onSettled?: () => void;
        }) => ({
          mutationFn: async (input: unknown) => {
            try {
              const result = await mockMutate(input);
              opts?.onSuccess?.();
              return result;
            } finally {
              opts?.onSettled?.();
            }
          },
        }),
      },
      delete: {
        mutationOptions: (opts: { onSuccess?: () => void }) => ({
          mutationFn: async (input: unknown) => {
            const result = await mockMutateAsync(input);
            opts?.onSuccess?.();
            return result;
          },
        }),
      },
    },
  },
}));

function createTestQueryClient() {
  return new QueryClient({
    defaultOptions: {
      queries: { retry: false },
      mutations: { retry: false },
    },
  });
}

function createWrapper() {
  const queryClient = createTestQueryClient();
  return ({ children }: { children: ReactNode }) =>
    createElement(QueryClientProvider, { client: queryClient }, children);
}

describe("useMessageEdits", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.useFakeTimers();
    _mockIsPending = false;
    mockMutate.mockResolvedValue(undefined);
    mockMutateAsync.mockResolvedValue(undefined);
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  describe("hasPendingEdits", () => {
    test("is false initially when no edits have been made", () => {
      const { result } = renderHook(
        () => useMessageEdits("import-1", "snap-1"),
        { wrapper: createWrapper() },
      );

      expect(result.current.hasPendingEdits).toBe(false);
    });

    test("is true immediately after saveEdit is called (debounce timer pending)", () => {
      const { result } = renderHook(
        () => useMessageEdits("import-1", "snap-1"),
        { wrapper: createWrapper() },
      );

      act(() => {
        result.current.saveEdit("msg-1", []);
      });

      expect(result.current.hasPendingEdits).toBe(true);
    });

    test("remains true while still within the 500ms debounce window", () => {
      const { result } = renderHook(
        () => useMessageEdits("import-1", "snap-1"),
        { wrapper: createWrapper() },
      );

      act(() => {
        result.current.saveEdit("msg-1", []);
      });

      act(() => {
        vi.advanceTimersByTime(400);
      });

      expect(result.current.hasPendingEdits).toBe(true);
    });

    test("stays true when multiple messages have pending debounce timers", () => {
      const { result } = renderHook(
        () => useMessageEdits("import-1", "snap-1"),
        { wrapper: createWrapper() },
      );

      act(() => {
        result.current.saveEdit("msg-1", []);
        result.current.saveEdit("msg-2", []);
      });

      expect(result.current.hasPendingEdits).toBe(true);
    });

    test("debounce timer is reset when saveEdit is called again for same message", () => {
      const { result } = renderHook(
        () => useMessageEdits("import-1", "snap-1"),
        { wrapper: createWrapper() },
      );

      act(() => {
        result.current.saveEdit("msg-1", []);
      });

      act(() => {
        vi.advanceTimersByTime(400);
      });

      act(() => {
        result.current.saveEdit("msg-1", [
          { type: "paragraph", text: "v2" } as never,
        ]);
      });

      expect(result.current.hasPendingEdits).toBe(true);
    });

    test("is false after deleteEdit cancels the pending debounce timer", async () => {
      const { result } = renderHook(
        () => useMessageEdits("import-1", "snap-1"),
        { wrapper: createWrapper() },
      );

      act(() => {
        result.current.saveEdit("msg-1", []);
      });

      expect(result.current.hasPendingEdits).toBe(true);

      await act(async () => {
        await result.current.deleteEdit("msg-1");
      });

      expect(result.current.hasPendingEdits).toBe(false);
    });
  });

  describe("hasPendingEdits with overlapping in-flight saves", () => {
    test("remains true while an older save is still in-flight after a newer one completes", async () => {
      /**
       * Given: Two messages both have their debounce timers fire, triggering
       *        two concurrent save mutations. The second mutation resolves
       *        first while the first is still in-flight.
       * When:  The second mutation settles.
       * Then:  hasPendingEdits must still be true because the first save is
       *        still running. It must only become false once both settle.
       */
      let resolveFirst!: () => void;
      let resolveSecond!: () => void;

      const firstSave = new Promise<void>((res) => {
        resolveFirst = res;
      });
      const secondSave = new Promise<void>((res) => {
        resolveSecond = res;
      });

      mockMutate.mockReturnValueOnce(firstSave).mockReturnValueOnce(secondSave);

      const { result } = renderHook(
        () => useMessageEdits("import-1", "snap-1"),
        { wrapper: createWrapper() },
      );

      act(() => {
        result.current.saveEdit("msg-1", []);
        result.current.saveEdit("msg-2", []);
      });

      await act(async () => {
        vi.advanceTimersByTime(600);
      });

      await act(async () => {
        resolveSecond();
        await secondSave;
      });

      expect(result.current.hasPendingEdits).toBe(true);

      await act(async () => {
        resolveFirst();
        await firstSave;
      });

      expect(result.current.hasPendingEdits).toBe(false);
    });
  });

  describe("isSaving (unchanged behavior)", () => {
    test("is false initially", () => {
      const { result } = renderHook(
        () => useMessageEdits("import-1", "snap-1"),
        { wrapper: createWrapper() },
      );

      expect(result.current.isSaving).toBe(false);
    });
  });
});

