      expect(screen.queryByTestId("toggle-edit-mode")).not.toBeInTheDocument();
    });

    test("hides edit button for json view", () => {
      renderToolbar({ view: "json" });

      expect(screen.queryByTestId("toggle-edit-mode")).not.toBeInTheDocument();
    });
  });

  describe("versions button visibility", () => {
