// @vitest-environment happy-dom
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import type { ImportSummary } from "@chat-exporter/shared";
import type { ReactNode } from "react";
import { beforeEach, describe, expect, test, vi } from "vitest";

import { DeleteImportDialog } from "./delete-import-dialog";

// --- Toast Mocks ---

const mockToastSuccess = vi.fn();

vi.mock("sonner", () => ({
  toast: Object.assign(vi.fn(), {
    info: vi.fn(),
    success: (...args: unknown[]) => mockToastSuccess(...args),
    error: vi.fn(),
  }),
}));

// --- RPC Mock ---

const mockDelete = vi.fn();

vi.mock("@/lib/rpc", () => ({
  rpc: {
    imports: {
      delete: (...args: unknown[]) => mockDelete(...args),
    },
  },
}));

// --- Helpers ---

function createTestQueryClient() {
  return new QueryClient({
    defaultOptions: {
      queries: { retry: false },
      mutations: { retry: false },
    },
  });
}

const fakeImport: ImportSummary = {
  id: "import-1",
  sourceUrl: "https://chatgpt.com/share/abc",
  pageTitle: "Test Chat",
  status: "completed",
  provider: "chatgpt",
  createdAt: new Date().toISOString(),
  updatedAt: new Date().toISOString(),
  messageCount: 10,
  currentStage: "done",
};

function renderDialog(props?: { onClose?: () => void; onDeleted?: () => void }) {
  const queryClient = createTestQueryClient();
  return render(
    <QueryClientProvider client={queryClient}>
      <DeleteImportDialog
        import_={fakeImport}
        onClose={props?.onClose ?? vi.fn()}
        onDeleted={props?.onDeleted ?? vi.fn()}
      />
    </QueryClientProvider>,
  );
}

// --- Polyfills ---

beforeAll(() => {
  Element.prototype.hasPointerCapture ??= vi.fn().mockReturnValue(false) as any;
  Element.prototype.setPointerCapture ??= vi.fn() as any;
  Element.prototype.releasePointerCapture ??= vi.fn() as any;
  Element.prototype.scrollIntoView ??= vi.fn() as any;
});

// --- Tests ---

describe("DeleteImportDialog toast feedback", () => {
  beforeEach(() => {
    mockToastSuccess.mockClear();
    mockDelete.mockReset();
  });

  test("shows success toast when import is deleted", async () => {
    const user = userEvent.setup();
    mockDelete.mockResolvedValue({ success: true });

    renderDialog();

    const deleteButton = screen.getByRole("button", { name: "Löschen" });
    await user.click(deleteButton);

    await waitFor(() => {
      expect(mockToastSuccess).toHaveBeenCalledWith("Import gelöscht");
    });
  });
});

// @vitest-environment happy-dom
import type { FormatRule } from "@chat-exporter/shared";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";

import { TooltipProvider } from "@/components/ui/tooltip";

import { RulesListModal } from "./rules-list-modal";

// ---------------------------------------------------------------------------
// Radix UI polyfills
// ---------------------------------------------------------------------------

beforeAll(() => {
  Element.prototype.hasPointerCapture ??= vi
    .fn()
    .mockReturnValue(false) as Element["hasPointerCapture"];
  Element.prototype.setPointerCapture ??=
    vi.fn() as Element["setPointerCapture"];
  Element.prototype.releasePointerCapture ??=
    vi.fn() as Element["releasePointerCapture"];
  Element.prototype.scrollIntoView ??= vi.fn() as Element["scrollIntoView"];
});

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function createRule(overrides: Partial<FormatRule> = {}): FormatRule {
  return {
    id: "rule-1",
    scope: "import_local",
    status: "active",
    instruction: "Test rule instruction",
    kind: "render",
    selector: { strategy: "exact", blockType: "paragraph", blockIndex: 0 },
    effect: {},
    createdAt: new Date().toISOString(),
    ...overrides,
  } as FormatRule;
}

type RenderModalOptions = {
  rules?: FormatRule[];
};

function renderModal(options: RenderModalOptions = {}) {
  const { rules = [createRule()] } = options;

  const props = {
    disablingRuleById: {} as Record<string, boolean>,
    expandedRuleId: null,
    explanationErrorById: {} as Record<string, string>,
    explanationLoadingById: {} as Record<string, boolean>,
    promotingRuleById: {} as Record<string, boolean>,
    rules,
    view: "reader" as const,
    getExplanationDetail: vi.fn().mockReturnValue(null),
    onDemoteRule: vi.fn(),
    onDisableRule: vi.fn(),
    onHoverRule: vi.fn(),
    onLeaveRule: vi.fn(),
    onPromoteRule: vi.fn(),
    onToggleRuleExplanation: vi.fn(),
  };

  return {
    ...render(
      <TooltipProvider delayDuration={0}>
        <RulesListModal {...props} />
      </TooltipProvider>,
    ),
    props,
  };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("RulesListModal", () => {
  describe("tooltips", () => {
    test("shows tooltip on rules trigger button hover", async () => {
      const user = userEvent.setup();
      renderModal();

      await user.hover(screen.getByTestId("rules-list-trigger"));

      await waitFor(() => {
        expect(
          screen.getByText("Aktive Formatierungsregeln anzeigen"),
        ).toBeInTheDocument();
      });
    });

    test("shows tooltip on promote button hover", async () => {
      const user = userEvent.setup();
      const localRule = createRule({ scope: "import_local" });
      renderModal({ rules: [localRule] });

      // Open the modal first
      await user.click(screen.getByTestId("rules-list-trigger"));
      await waitFor(() => {
        expect(screen.getByTestId("rules-list-promote")).toBeInTheDocument();
      });

      await user.hover(screen.getByTestId("rules-list-promote"));

      await waitFor(() => {
        expect(
          screen.getByText("Regel auf alle Imports übertragen"),
        ).toBeInTheDocument();
      });
    });

    test("shows tooltip on demote button hover", async () => {
      const user = userEvent.setup();
      const globalRule = createRule({ scope: "format_profile" });
      renderModal({ rules: [globalRule] });

      // Open the modal first
      await user.click(screen.getByTestId("rules-list-trigger"));
      await waitFor(() => {
        expect(screen.getByTestId("rules-list-demote")).toBeInTheDocument();
      });

      await user.hover(screen.getByTestId("rules-list-demote"));

      await waitFor(() => {
        expect(
          screen.getByText("Regel auf diesen Import beschränken"),
        ).toBeInTheDocument();
      });
    });

    test("shows tooltip on disable button hover", async () => {
      const user = userEvent.setup();
      renderModal();

      // Open the modal first
      await user.click(screen.getByTestId("rules-list-trigger"));
      await waitFor(() => {
        expect(screen.getByTestId("rules-list-disable")).toBeInTheDocument();
      });

      await user.hover(screen.getByTestId("rules-list-disable"));

      await waitFor(() => {
        expect(
          screen.getByText("Regel deaktivieren"),
        ).toBeInTheDocument();
      });
    });
  });
});

