 40→function formatSourceLabel(url: string) {
 41→  try {
 42→    const parsed = new URL(url);
 43→    const value =
 44→      `${parsed.hostname.replace(/^www\./, "")}${parsed.pathname}`.replace(
 45→        /\/$/,
 46→        "",
 47→      );
 48→    return value.length > 46 ? `${value.slice(0, 43)}...` : value;
 49→  } catch {
 50→    return url.length > 46 ? `${url.slice(0, 43)}...` : url;
 51→  }
 52→}
