 54→function formatElapsed(ms: number) {
 55→  if (!Number.isFinite(ms) || ms < 0) {
 56→    return "00:00";
 57→  }
 58→
 59→  const totalSeconds = Math.floor(ms / 1000);
 60→  const seconds = totalSeconds % 60;
 61→  const minutes = Math.floor(totalSeconds / 60) % 60;
 62→  const hours = Math.floor(totalSeconds / 3600);
 63→
 64→  if (hours > 0) {
 65→    return `${hours}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
 66→  }
 67→
 68→  return `${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
 69→}
