  1→import type {
  2→  AdjustmentSessionDetail,
  3→  FormatRule,
  4→} from "@chat-exporter/shared";
  5→import {
  6→  ArrowDown,
  7→  ArrowUp,
  8→  ChevronDown,
  9→  ChevronRight,
 10→  Globe,
 11→  Loader2,
 12→  Search,
 13→  X,
 14→} from "lucide-react";
 15→import { useMemo, useRef, useState } from "react";
 16→import {
 17→  getBlockTypeLabel,
 18→  getRuleLabel,
 19→  rulesLabels,
 20→} from "@/components/format-workspace/labels";
 21→import { describeSelectorScope } from "@/components/format-workspace/rule-scope";
 22→import type { ViewMode } from "@/components/format-workspace/types";
 23→import { Button } from "@/components/ui/button";
 24→import {
 25→  Dialog,
 26→  DialogContent,
 27→  DialogDescription,
 28→  DialogHeader,
 29→  DialogTitle,
 30→  DialogTrigger,
 31→} from "@/components/ui/dialog";
 32→import { Input } from "@/components/ui/input";
 33→
 34→type SortKey = "title" | "scope" | "date";
 35→type SortDir = "asc" | "desc";
 36→
 37→type RulesListModalProps = {
 38→  disablingRuleById: Record<string, boolean>;
 39→  expandedRuleId: string | null;
 40→  explanationErrorById: Record<string, string>;
 41→  explanationLoadingById: Record<string, boolean>;
 42→  promotingRuleById: Record<string, boolean>;
 43→  rules: FormatRule[];
 44→  view: ViewMode;
 45→  getExplanationDetail: (rule: FormatRule) => AdjustmentSessionDetail | null;
 46→  onDemoteRule: (ruleId: string) => void;
 47→  onDisableRule: (ruleId: string) => void;
 48→  onHoverRule: (ruleId: string) => void;
 49→  onLeaveRule: () => void;
 50→  onPromoteRule: (ruleId: string) => void;
 51→  onToggleRuleExplanation: (rule: FormatRule) => void;
 52→};
 53→
 54→const modalLabels = {
 55→  title: "Formatierungsregeln",
 56→  description: "Alle aktiven Regeln für diesen Import verwalten.",
 57→  searchPlaceholder: "Regeln durchsuchen...",
 58→  noResults: "Keine Regeln gefunden.",
 59→  scopeAll: "Alle Imports",
 60→  scopeLocal: "Nur dieser Import",
 61→  disable: "Deaktivieren",
 62→  disabling: "Wird deaktiviert...",
 63→  delete: "Löschen",
 64→  deleting: "Wird gelöscht...",
 65→  colRule: "Regel",
 66→  colScope: "Geltungsbereich",
 67→  colActions: "Aktionen",
 68→} as const;
 69→
 70→const scopeOrder: Record<string, number> = {
 71→  import_local: 0,
 72→  format_profile: 1,
 73→};
 74→
 75→function sortRules(
 76→  rules: FormatRule[],
 77→  sortKey: SortKey,
 78→  sortDir: SortDir,
 79→): FormatRule[] {
 80→  return [...rules].sort((a, b) => {
 81→    let cmp: number;
 82→    switch (sortKey) {
 83→      case "title":
 84→        cmp = a.instruction.localeCompare(b.instruction, "de");
 85→        break;
 86→      case "scope":
 87→        cmp = (scopeOrder[a.scope] ?? 2) - (scopeOrder[b.scope] ?? 2);
 88→        break;
 89→      default:
 90→        cmp = new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
 91→        break;
 92→    }
 93→    return sortDir === "desc" ? -cmp : cmp;
 94→  });
 95→}
 96→
 97→function describeSelectorStrategy(selector: unknown): string {
 98→  const s =
 99→    selector && typeof selector === "object"
100→      ? (selector as Record<string, unknown>)
101→      : null;
102→  if (!s) return "Unbekannter Selektor";
103→
104→  const strategy = s.strategy as string | undefined;
105→  const blockType =
106→    typeof s.blockType === "string" ? getBlockTypeLabel(s.blockType) : null;
107→
108→  switch (strategy) {
109→    case "exact":
110→      return blockType
111→        ? `Exakter Block: ${blockType} #${(s.blockIndex as number) + 1}`
112→        : "Exakter Block";
113→    case "block_type":
114→      return blockType
115→        ? `Alle Blöcke vom Typ: ${blockType}`
116→        : "Alle Blöcke eines Typs";
117→    case "prefix_before_colon":
118→      return blockType
119→        ? `Präfix vor Doppelpunkt in: ${blockType}`
120→        : "Präfix vor Doppelpunkt";
121→    case "markdown_table":
122→      return "Alle Markdown-Tabellen";
123→    case "compound": {
124→      const parts: string[] = [];
125→
126→      if (blockType) parts.push(blockType);
127→
128→      const role = typeof s.messageRole === "string" ? s.messageRole : null;
129→      if (role) parts.push(`Rolle: ${role}`);
130→
131→      const level = typeof s.headingLevel === "number" ? s.headingLevel : null;
132→      if (level) parts.push(`H${level}`);
133→
134→      const pos = typeof s.position === "string" ? s.position : null;
135→      if (pos) parts.push(pos === "first" ? "Erster Block" : "Letzter Block");
136→
137→      const pattern = typeof s.textPattern === "string" ? s.textPattern : null;
138→      if (pattern) parts.push(`Pattern: "${pattern}"`);
139→
140→      const ctx =
141→        s.context && typeof s.context === "object"
142→          ? (s.context as Record<string, unknown>)
143→          : null;
144→      if (ctx?.previousSibling) parts.push("nach bestimmtem Block");
145→      if (ctx?.nextSibling) parts.push("vor bestimmtem Block");
146→
147→      return parts.length > 0
148→        ? `Compound: ${parts.join(", ")}`
149→        : "Compound-Filter (alle Blöcke)";
150→    }
151→    default:
