176→  onHoverRule,
177→  onLeaveRule,
178→  onPromoteRule,
179→  onToggleRuleExplanation,
180→}: RulesListModalProps) {
181→  const [search, setSearch] = useState("");
182→  const [sortKey, setSortKey] = useState<SortKey>("date");
183→  const [sortDir, setSortDir] = useState<SortDir>("desc");
184→  const searchRef = useRef<HTMLInputElement>(null);
185→
186→  const activeRules = rules.filter((rule) => rule.status === "active");
