203→      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
204→    } else {
205→      setSortKey(key);
206→      setSortDir("asc");
207→    }
208→  }
209→
210→  return (
211→    <Dialog
212→      onOpenChange={(open) => {
